import{_ as a,o as t,c as o,a3 as l}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"168. On Call Recall","description":"","frontmatter":{"title":"168. On Call Recall","eba":"Mental Health Services 2024-2028","topics":["leave","public-holidays","allowances"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/168-on-call-recall.md","filePath":"ebas/mental-health/support-services/preliminary/168-on-call-recall.md"}'),r={name:"ebas/mental-health/support-services/preliminary/168-on-call-recall.md"};function n(s,e,h,i,c,p){return t(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="_168-on-call-recall" tabindex="-1">168. On Call Recall <a class="header-anchor" href="#_168-on-call-recall" aria-label="Permalink to &quot;168. On Call Recall&quot;">​</a></h1><p><strong>168.1</strong> The Employer shall pay an on-call allowance to Employees who are required to be on call.</p><p><strong>168.2</strong> On-call Allowance</p><p><strong>(a)</strong> An Employee rostered to be on-call will be paid the &#39;on-call allowance&#39; set in Appendix 2 per 12-hour period or part thereof commencing with the following rates:</p><p><strong>(i)</strong> Monday to Friday – as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>(ii)</strong> Saturday – as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a></p><p><strong>(iii)</strong> Sunday or public holiday – as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>; and</p><p><strong>(iv)</strong> Weekend public holiday – as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>(b)</strong> The telephone allowance in the 2020 Agreement does not apply from FFPPOA 20 May 2025 and has been included in the rates at 168.2(a) above.</p><p><strong>(c)</strong> An Employee rostered to be on-call for a period spanning two days over which two different on-call allowances apply will receive a payment which is equal to the allowance payable for the day attracting the higher allowance.</p><p><strong>168.3</strong> Recall</p><p><strong>(a)</strong> Any period of overtime involving a recall to duty during an off-duty period, and which is not continuous with the next succeeding rostered period of duty, shall be paid at a minimum of three hours at the appropriate overtime rate.</p><p><strong>168.4</strong> Additional provisions</p><p><strong>(a)</strong> When recall work is necessary, it should be so arranged that Employees have at least 10 hours off duty between successive shifts.</p><p><strong>(b)</strong> An Employee, other than a casual, who works so much overtime between the termination of their previous rostered shift an the commencement of their next rostered shift, that they would not have a 10-hour break shall be released after completion of such recall worked until they have had a 10-hour break. The Employee shall not suffer any loss of pay for rostered ordinary hours occurring during such absence.</p><p><strong>(c)</strong> If, on the instructions of the Employer, an Employee resumes or continues work without having had a 10-hour break in accordance with clause 168.4(b)[183.2(d)], they shall be paid at the rate of double time until they are released from duty for such rest period. The Employee shall then be entitled to be absent until they have had a 10-hour break. The Employee shall not suffer any loss of pay for rostered ordinary hours occurring during such absence.</p><p><strong>168.5</strong> Transport following Recall</p><p><strong>(a)</strong> Where an Employee finishes a period of recall at a time when reasonable means of transport are not available for them to return to their place of residence, the Employer shall provide adequate transport free of charge.</p><p><strong>168.6</strong> The on-call allowances are calculated at the rate of 2.5% of the “Patient Services Assistant Level 2” rate of pay pursuant to <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p>',19)])])}const m=a(r,[["render",n]]);export{u as __pageData,m as default};
